('business:5-5-cash-and-cash-flow:match:7971503d', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cash Flow Forecast”?", "options": ["Total inflow minus total outflow for a given period.", "The amount of cash available at the beginning of the month; equal to the previous month''s closing balance.", "The amount of cash left at the end of the month; becomes the opening balance for the next month.", "A statement showing the expected flow of money into and out of a business over a period of time."]}'::jsonb, '{"answer": 3, "explain": "“Cash Flow Forecast” means: A statement showing the expected flow of money into and out of a business over a period of time."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:cd54f93c', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Net Cash Flow”?", "options": ["The amount of cash available at the beginning of the month; equal to the previous month''s closing balance.", "The amount of cash left at the end of the month; becomes the opening balance for the next month.", "The ability of a business to pay its short-term debts which must be paid in the near future.", "Total inflow minus total outflow for a given period."]}'::jsonb, '{"answer": 3, "explain": "“Net Cash Flow” means: Total inflow minus total outflow for a given period."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:49a3b2f3', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Opening Balance”?", "options": ["The amount of cash left at the end of the month; becomes the opening balance for the next month.", "The ability of a business to pay its short-term debts which must be paid in the near future.", "When more cash flows into the business than flows out during a month (a cash flow surplus).", "The amount of cash available at the beginning of the month; equal to the previous month''s closing balance."]}'::jsonb, '{"answer": 3, "explain": "“Opening Balance” means: The amount of cash available at the beginning of the month; equal to the previous month''s closing balance."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:5a17a7f6', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Closing Balance”?", "options": ["The ability of a business to pay its short-term debts which must be paid in the near future.", "When more cash flows into the business than flows out during a month (a cash flow surplus).", "The amount of cash left at the end of the month; becomes the opening balance for the next month.", "When more cash flows out of the business than flows in during a month (a cash flow deficit)."]}'::jsonb, '{"answer": 2, "explain": "“Closing Balance” means: The amount of cash left at the end of the month; becomes the opening balance for the next month."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:b30d9314', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Liquidity”?", "options": ["When more cash flows into the business than flows out during a month (a cash flow surplus).", "When more cash flows out of the business than flows in during a month (a cash flow deficit).", "Money held in bank accounts and on the premises; not simply notes and coins.", "The ability of a business to pay its short-term debts which must be paid in the near future."]}'::jsonb, '{"answer": 3, "explain": "“Liquidity” means: The ability of a business to pay its short-term debts which must be paid in the near future."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:99777cac', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Positive Cash Flow”?", "options": ["When more cash flows out of the business than flows in during a month (a cash flow deficit).", "Money held in bank accounts and on the premises; not simply notes and coins.", "Revenue received by a business minus the total costs of running the business.", "When more cash flows into the business than flows out during a month (a cash flow surplus)."]}'::jsonb, '{"answer": 3, "explain": "“Positive Cash Flow” means: When more cash flows into the business than flows out during a month (a cash flow surplus)."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:ee47a358', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Negative Cash Flow”?", "options": ["Money held in bank accounts and on the premises; not simply notes and coins.", "Revenue received by a business minus the total costs of running the business.", "Money that the business pays out.", "When more cash flows out of the business than flows in during a month (a cash flow deficit)."]}'::jsonb, '{"answer": 3, "explain": "“Negative Cash Flow” means: When more cash flows out of the business than flows in during a month (a cash flow deficit)."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:95f83199', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Cash”?", "options": ["Money held in bank accounts and on the premises; not simply notes and coins.", "Revenue received by a business minus the total costs of running the business.", "Money that the business pays out.", "A short-term bank arrangement allowing a business to spend more than its current bank balance up to an agreed limit."]}'::jsonb, '{"answer": 0, "explain": "“Cash” means: Money held in bank accounts and on the premises; not simply notes and coins."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:1180f064', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit”?", "options": ["Money that the business pays out.", "Revenue received by a business minus the total costs of running the business.", "A short-term bank arrangement allowing a business to spend more than its current bank balance up to an agreed limit.", "The total amount of cash flowing into a business in a given period, including sales revenue and any other receipts."]}'::jsonb, '{"answer": 1, "explain": "“Profit” means: Revenue received by a business minus the total costs of running the business."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:c709f18f', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Expenditure”?", "options": ["A short-term bank arrangement allowing a business to spend more than its current bank balance up to an agreed limit.", "The total amount of cash flowing into a business in a given period, including sales revenue and any other receipts.", "Money that the business pays out.", "A statement showing the expected flow of money into and out of a business over a period of time."]}'::jsonb, '{"answer": 2, "explain": "“Expenditure” means: Money that the business pays out."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:1c20b892', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Overdraft”?", "options": ["The total amount of cash flowing into a business in a given period, including sales revenue and any other receipts.", "A statement showing the expected flow of money into and out of a business over a period of time.", "A short-term bank arrangement allowing a business to spend more than its current bank balance up to an agreed limit.", "Total inflow minus total outflow for a given period."]}'::jsonb, '{"answer": 2, "explain": "“Overdraft” means: A short-term bank arrangement allowing a business to spend more than its current bank balance up to an agreed limit."}'::jsonb),
('business:5-5-cash-and-cash-flow:match:4c062c6f', 'business', 'business:5-5-cash-and-cash-flow', '5.5 Cash and Cash Flow', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total Inflow”?", "options": ["The total amount of cash flowing into a business in a given period, including sales revenue and any other receipts.", "A statement showing the expected flow of money into and out of a business over a period of time.", "Total inflow minus total outflow for a given period.", "The amount of cash available at the beginning of the month; equal to the previous month''s closing balance."]}'::jsonb, '{"answer": 0, "explain": "“Total Inflow” means: The total amount of cash flowing into a business in a given period, including sales revenue and any other receipts."}'::jsonb),
('business:6-1-ethical-environmental:exam:cbd1bd58', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'exam', 'mcq', 1, '{"num": "Q2", "question": "A health centre wishes to improve its environmental sustainability. Which of the following would help achieve this? [1 mark]", "options": ["Asking doctors to wash their hands more frequently", "Encouraging nurses to go out walking during their lunch break", "Giving out free fruit to health centre staff and patients", "Installing sensors to switch off lights when not needed"], "hint": "Environmental sustainability means reducing the impact on the natural world. Which option directly saves energy or resources?"}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n  <h5>Correct answer: D</h5>\n  <p>Installing sensors to switch off lights when not needed directly reduces energy consumption, improving the environmental sustainability of the health centre.</p>\n  <p>Options A, B, and C all relate to health or wellbeing of staff and patients — they are not environmental sustainability measures.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('business:6-1-ethical-environmental:exam:3bb94dd4', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A business wishes to be known as an ethical employer. Which of the following is NOT an example of ethical treatment of the workforce? [1 mark]", "options": ["Allowing flexible working", "Paying high wages", "Providing good working conditions", "Using robotics"], "hint": "The question asks for what is NOT ethical treatment of workers. Three options clearly benefit employees directly. Which one is about business efficiency rather than how workers are treated?"}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n  <h5>Correct answer: D — Using robotics</h5>\n  <p>Using robotics is about production technology and business efficiency — it does not directly represent ethical treatment of the workforce.</p>\n  <ul>\n    <li>Flexible working (A) — directly benefits workers</li>\n    <li>Paying high wages (B) — directly benefits workers</li>\n    <li>Good working conditions (C) — directly benefits workers</li>\n    <li>Using robotics (D) — relates to production, not the ethical treatment of employees</li>\n  </ul>\n</div>", "modelAnswer": ""}'::jsonb),
('business:6-1-ethical-environmental:exam:9f298d5f', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'exam', 'mcq', 1, '{"num": "Q10", "question": "Which of the following issues is climate change an example of? [1 mark]", "options": ["A financial issue", "A quality control issue", "An economic issue", "An environmental issue"], "hint": "Climate change concerns the long-term impact of human activity on the natural world. Which category does that belong to?"}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n  <h5>Correct answer: D — An environmental issue</h5>\n  <p>Climate change is an environmental issue — it concerns the impact of human activity on the natural world, including rising global temperatures and changing weather patterns. It is not primarily a financial, quality control, or economic issue.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('business:6-1-ethical-environmental:mcq:c57ab4e4', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "What is the definition of ''Ethics'' in business?", "options": ["Following the basic laws of the country", "Focusing on what is the ''right'' or ''wrong'' thing to do", "Maximizing profit at all costs", "Reducing the carbon footprint of a factory"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Ethics goes beyond the law and focuses on moral principles of right and wrong."}'::jsonb),
('business:6-1-ethical-environmental:mcq:39535268', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Which of the following is an example of a renewable resource?", "options": ["Coal", "Oil", "Natural Gas", "Wind power"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: D. Wind power can be used more than once and does not run out, making it renewable."}'::jsonb),
('business:6-1-ethical-environmental:mcq:71166736', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "What does ''Fairtrade'' encourage businesses to do?", "options": ["Pay the legal minimum wage in the UK", "Pay a fair price to suppliers in developing countries", "Trade goods without paying taxes", "Use child labour to keep costs fair for consumers"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Fairtrade ensures suppliers and farmers in developing nations receive a fair, livable price for their goods."}'::jsonb),
('business:6-1-ethical-environmental:mcq:9fc88435', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Sustainable production means:", "options": ["Producing goods as cheaply as possible", "Production that does not lead to the depletion of natural resources", "Producing goods that last a long time before breaking", "Using non-renewable resources exclusively"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Sustainability ensures we do not use up natural resources, leaving them available for future generations."}'::jsonb),
('business:6-1-ethical-environmental:mcq:6f4fe435', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Which of the following is a major DISADVANTAGE of a business choosing to act ethically?", "options": ["It improves the brand''s reputation", "Employees are more motivated to work there", "It usually results in higher production costs", "Customers refuse to buy ethical products"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Paying fair wages, sourcing Fairtrade materials, and using safe conditions all increase the costs of production."}'::jsonb),
('business:6-1-ethical-environmental:mcq:a9a8096a', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Which of the following is an ENVIRONMENTAL consideration (rather than an ethical one)?", "options": ["Paying suppliers on time", "Safe waste disposal and recycling", "Refusing to use child labour", "Not making false claims in advertising"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Waste disposal directly affects the physical planet, making it an environmental issue. The others are ethical issues regarding how people are treated."}'::jsonb),
('business:6-1-ethical-environmental:mcq:8f1f5127', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Child labour is defined as:", "options": ["Employing anyone under the age of 21", "Using young children below the legal age for employment to achieve low-cost production", "Allowing children to visit their parents at work", "Selling products specifically designed for children"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Child labour is an unethical practice used to exploit young, under-age workers for cheap labour."}'::jsonb),
('business:6-1-ethical-environmental:mcq:7adc472d', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "If an ethical business faces competitors who use unethical, cheap labour, what is a likely consequence?", "options": ["The ethical business will automatically have a monopoly", "The ethical business might struggle to compete on price", "The unethical competitors will immediately be shut down by the UN", "The ethical business''s costs will magically drop"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Unethical businesses have lower costs and can charge lower prices, potentially stealing price-sensitive customers from the ethical business."}'::jsonb),
('business:6-1-ethical-environmental:mcq:43669233', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "How can being environmentally friendly benefit a business''s marketing?", "options": ["It allows them to ignore consumer laws", "It provides a Unique Selling Point (USP) that attracts green consumers", "It increases their carbon emissions", "It guarantees they will never make a loss"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Being ''green'' improves reputation and acts as a strong USP, allowing the business to market themselves positively."}'::jsonb),
('business:6-1-ethical-environmental:mcq:f6935417', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "A business delays paying its bills to small suppliers for 6 months to improve its own cash flow. This is considered:", "options": ["Environmentally friendly", "Fairtrade", "Unethical", "Sustainable"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C. Poor treatment of suppliers (like late payments) is an unethical business practice."}'::jsonb),
('business:6-1-ethical-environmental:mcq:4c22dac8', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Woody''s Caravan Park switched to electric vehicles and solar panels. This primarily addresses which environmental issue?", "options": ["Child labour", "Climate change and carbon emissions", "False advertising", "Fairtrade sourcing"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Electric vehicles and solar panels directly reduce carbon emissions, combating climate change."}'::jsonb),
('business:6-1-ethical-environmental:mcq:765ab951', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'mcq', 'mcq', 1, '{"question": "Why might a business choose to ignore environmental considerations?", "options": ["Because consumers hate green products", "To avoid the high costs of installing new green technology and renewable energy", "Because the government forces them to pollute", "Because renewable energy is illegal"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. Implementing green technology (like Olleco''s R&D or installing solar panels) is very expensive in the short term."}'::jsonb),
('business:6-1-ethical-environmental:tf:0c4f6799', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Ethics in business is solely about obeying the legal laws of the country."}'::jsonb, '{"answer": false, "explain": "FALSE. Ethics goes beyond the law; it involves doing what is morally ''right'', even if the law does not strictly require it."}'::jsonb),
('business:6-1-ethical-environmental:tf:3a2f3a10', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Child labour is used by some unethical businesses to achieve low-cost production."}'::jsonb, '{"answer": true, "explain": "TRUE. Unethical businesses exploit under-age workers because they can be paid extremely low wages."}'::jsonb),
('business:6-1-ethical-environmental:tf:bcf91909', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Fairtrade guarantees that consumers will get the cheapest possible price in the supermarket."}'::jsonb, '{"answer": false, "explain": "FALSE. Fairtrade usually results in slightly higher prices for consumers, because it guarantees a fair, higher price is paid to the farmers/suppliers."}'::jsonb),
('business:6-1-ethical-environmental:tf:91514a18', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Oil and natural gas are examples of renewable resources."}'::jsonb, '{"answer": false, "explain": "FALSE. Oil and gas are non-renewable because they can only be used once and will eventually run out."}'::jsonb),
('business:6-1-ethical-environmental:tf:e7f33402', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "A major disadvantage of installing environmentally friendly technology is the high initial cost."}'::jsonb, '{"answer": true, "explain": "TRUE. Things like solar panels, electric vehicles, and researching biofuels require significant financial investment."}'::jsonb),
('business:6-1-ethical-environmental:tf:7d606501', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Making false claims in an advertisement is considered an ethical marketing practice."}'::jsonb, '{"answer": false, "explain": "FALSE. Lying or misleading customers is highly unethical (and often illegal)."}'::jsonb),
('business:6-1-ethical-environmental:tf:06c75eae', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Sustainable production ensures that natural resources are not depleted for future generations."}'::jsonb, '{"answer": true, "explain": "TRUE. Sustainability is about balancing current needs without ruining the planet for the future."}'::jsonb),
('business:6-1-ethical-environmental:tf:7f8a3199', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "An ethical business will never have a competitive advantage."}'::jsonb, '{"answer": false, "explain": "FALSE. Acting ethically can be a Unique Selling Point (USP), improving reputation and attracting loyal customers willing to pay premium prices."}'::jsonb),
('business:6-1-ethical-environmental:tf:5f318c7e', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Treating suppliers ethically includes paying their invoices on time."}'::jsonb, '{"answer": true, "explain": "TRUE. Deliberately delaying payments to suppliers can ruin small businesses and is considered unethical."}'::jsonb),
('business:6-1-ethical-environmental:tf:178b72f5', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Environmentally friendly policies have no impact on employee motivation."}'::jsonb, '{"answer": false, "explain": "FALSE. Employees are generally much more motivated and proud to work for a company that respects the environment and treats people well."}'::jsonb),
('business:6-1-ethical-environmental:tf:0a5f0917', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "Reducing carbon emissions helps a business combat climate change."}'::jsonb, '{"answer": true, "explain": "TRUE. Switching to electric vehicles or renewable energy reduces emissions and lessens environmental impact."}'::jsonb),
('business:6-1-ethical-environmental:tf:d67547a1', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tf', 'tf', 1, '{"question": "All competitors in a market will always act ethically."}'::jsonb, '{"answer": false, "explain": "FALSE. Many businesses choose to act unethically to keep costs low and maximize their own profits."}'::jsonb),
('business:6-1-ethical-environmental:learn:4738efd3', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Core Definitions — Ethics & Environment", "reading": "<ul>\n<li><strong>Ethics</strong> — what is right and wrong</li>\n<li><strong>Ethical behaviour</strong> — doing what is morally right; concerns how workers, suppliers and customers are treated</li>\n<li><strong>Child labour</strong> — the use of young children below the legal age for employment to achieve low-cost production</li>\n<li><strong>Fairtrade</strong> — a movement encouraging businesses to pay a fair price to suppliers in developing countries; the Fairtrade Mark guarantees this</li>\n<li><strong>Environmentally friendly</strong> — consumers and businesses that act to make production sustainable</li>\n<li><strong>Sustainable production</strong> — production that does not lead to the depletion (using up) of natural resources</li>\n<li><strong>Renewable resources</strong> — resources that can be used more than once (wind, water, crops)</li>\n<li><strong>Non-renewable resources</strong> — resources that can only be used once (e.g. oil)</li>\n<li><strong>Recycling</strong> — when resources are reused to produce something new</li>\n</ul>", "question": "According to the key definitions, what does ''sustainable production'' mean?", "options": ["Production that does not lead to the depletion of natural resources", "Production that uses only recycled materials for every single product", "Production that maximises profit regardless of environmental impact", "Production that relies entirely on non-renewable resources like oil"]}'::jsonb, '{"answer": 0, "explain": "The card defines sustainable production as production that does not deplete natural resources — distinct from recycling, profit-maximising, or relying on non-renewables."}'::jsonb),
('business:6-1-ethical-environmental:learn:c1ad81eb', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Four Areas of Ethical Consideration", "reading": "<p><strong>1. Treatment of Workers</strong></p>\n<ul>\n<li>No child labour</li>\n<li>Pay at least the National Minimum/Living Wage</li>\n<li>Fair hours — no excessive working hours</li>\n<li>Safe working conditions</li>\n<li>No discrimination on gender, ethnicity or disability grounds</li>\n</ul>\n<p><strong>2. Treatment of Suppliers</strong></p>\n<ul>\n<li>No late payment of bills (harms supplier cash flow)</li>\n<li>Pay fair prices</li>\n<li>Do not use power to force smaller suppliers into lower-priced deals</li>\n</ul>\n<p><strong>3. Treatment of Customers</strong></p>\n<ul>\n<li>No overcharging / exorbitant prices</li>\n<li>No false claims — marketing must be legal, decent, honest and truthful</li>\n<li>Do not put customers in danger with fake or faulty products</li>\n</ul>\n<p><strong>4. Sourcing of Materials</strong></p>\n<ul>\n<li>Do not buy from businesses that use child labour</li>\n<li>Do not buy from anyone who does not produce sustainably</li>\n<li>Consider using the Fairtrade Mark — guarantees a fair price was paid to farmers</li>\n</ul>", "question": "Which of these is listed under ''Treatment of Suppliers'' in this card?", "options": ["No discrimination on the grounds of gender, ethnicity or disability", "No late payment of bills, since this harms a supplier''s cash flow", "No overcharging or exorbitant prices charged to customers", "No false claims made in marketing that must be honest and truthful"]}'::jsonb, '{"answer": 1, "explain": "The card lists no late payment of bills under Treatment of Suppliers; discrimination relates to workers, overcharging and false claims relate to customers."}'::jsonb),
('business:6-1-ethical-environmental:learn:9e50a56e', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Benefits & Drawbacks of Being Ethical", "reading": "<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits</div>\n<div class=\"pro-item\">Improved reputation — more customers buy from trustworthy businesses</div>\n<div class=\"pro-item\">Increased sales — ethical brands attract customers willing to pay more</div>\n<div class=\"pro-item\">Worker motivation — trust increases productivity; reduces labour turnover and recruitment costs</div>\n<div class=\"pro-item\">Investor confidence — long-term success attracts investors</div>\n<div class=\"pro-item\">Long-term survival — ethical producers more likely to be profitable over time</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Drawbacks</div>\n<div class=\"con-item\">Higher costs — better materials, fair wages and ethical sourcing all cost more</div>\n<div class=\"con-item\">Reduced profits — higher costs cut into profit margins</div>\n<div class=\"con-item\">Lost sales — unethical competitors can charge less, making the ethical business less competitive</div>\n<div class=\"con-item\">Threat to survival — in highly competitive markets, extra costs may threaten existence</div>\n</div>\n</div>", "question": "According to this card, what is a drawback of being an ethical business?", "options": ["Lower sales, since ethical brands never attract any customers at all", "Reduced investor confidence, since investors avoid ethical businesses", "Higher costs, since better materials and fair wages cost more money", "Higher staff turnover, since ethical treatment reduces worker motivation"]}'::jsonb, '{"answer": 2, "explain": "The card lists higher costs as a drawback of ethical behaviour — the other options contradict the benefits listed, such as increased sales and worker motivation."}'::jsonb),
('business:6-1-ethical-environmental:learn:b76438b3', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Key Environmental Issues", "reading": "<ul>\n<li><strong>Pollution</strong> — causing harm to the environment: air, land, water and noise</li>\n<li><strong>Waste disposal</strong> — getting rid of unwanted materials; traditionally via incineration or landfill</li>\n<li><strong>Recycling</strong> — reusing resources to produce something new</li>\n<li><strong>Climate change</strong> — the process where average temperatures rise or fall and weather patterns change</li>\n<li><strong>Global warming</strong> — rise in average temperatures caused by human activity (burning fossil fuels, deforestation)</li>\n</ul>\n<p><strong>Sustainable production methods:</strong></p>\n<ul>\n<li><strong>Renewable energy</strong> — solar and wind power instead of fossil fuels</li>\n<li><strong>Sustainable construction</strong> — recycled materials, insulation, solar panels built in</li>\n<li><strong>Resource management</strong> — rotating crops, fixing water leaks, sensor-controlled lighting</li>\n<li><strong>Transport</strong> — fuel-efficient vehicles, car-sharing, video-conferencing to reduce travel</li>\n</ul>", "question": "According to this card, what is the difference between climate change and global warming?", "options": ["Climate change and global warming are simply two different names for pollution", "Climate change only affects water, while global warming only affects land", "Global warming is simply a form of recycling, while climate change is a form of waste disposal", "Climate change is broader weather-pattern change; global warming is the specific temperature rise"]}'::jsonb, '{"answer": 3, "explain": "The card defines climate change as changing weather patterns and global warming specifically as the rise in average temperatures caused by human activity."}'::jsonb),
('business:6-1-ethical-environmental:learn:07225cc3', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Benefits & Drawbacks of Being Environmentally Friendly", "reading": "<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ Benefits</div>\n<div class=\"pro-item\">Increased sales — consumers increasingly choose ''green'' brands</div>\n<div class=\"pro-item\">Reduced costs — energy-saving bulbs, solar panels, reduced packaging save money long-term</div>\n<div class=\"pro-item\">Reduced tax bills — less pollution = potential tax reductions</div>\n<div class=\"pro-item\">Government subsidies — grants available for eco-friendly products and processes</div>\n<div class=\"pro-item\">Better reputation and marketing opportunities</div>\n</div>\n<div>\n<div class=\"col-head\">✗ Drawbacks</div>\n<div class=\"con-item\">Raw material costs — environmentally friendly materials often cost more</div>\n<div class=\"con-item\">Capital costs — solar panels, anaerobic digesters are very expensive to install</div>\n<div class=\"con-item\">Expensive production methods — organic farming costs more than using fertilisers and pesticides</div>\n</div>\n</div>", "question": "According to this card, how can being environmentally friendly reduce a business''s costs?", "options": ["Energy-saving measures like solar panels and reduced packaging save money long-term", "Environmentally friendly materials are always cheaper than the standard materials", "Government subsidies fully cover every environmental cost a business faces", "Organic farming always costs less than using fertilisers and pesticides"]}'::jsonb, '{"answer": 0, "explain": "The card lists reduced costs from energy-saving measures as a benefit; it also notes environmental materials, organic farming and capital costs are often MORE expensive, not less."}'::jsonb),
('business:6-1-ethical-environmental:learn:69c675c8', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Key Case Studies", "reading": "<p><strong>Pukka Teas (Fairtrade ethics):</strong> Certified ''Fair for Life'' producer. Turnover grew from £9m (2012) to £45m (2019) — proof ethical businesses can thrive. Cost: paid £148,000 into a Fairtrade community fund in 2017.</p>\n<p><strong>Olleco (Sustainability):</strong> Collects waste cooking oil/food to produce biodiesel. Revenue exceeds £220m across 19 UK sites. Cost: spent millions on R&D and specialist processing plants (anaerobic digesters).</p>\n<p><strong>Tesco (Unethical supplier treatment):</strong> Found guilty of delaying payments to small suppliers — one waited 24 months for £2 million, damaging their cash flow.</p>\n<p><strong>Unilever (Environment):</strong> Aims to halve greenhouse gas emissions by 2030 through ''cool blending'' and compressed packaging.</p>\n<p><strong>Shanks plc (Waste):</strong> Turns rubbish into fuel, compost and wood products instead of landfill — ''waste to product'' process.</p>\n<p><strong>Boohoo (Unethical sourcing):</strong> Faced heavy criticism in 2020/21 for supplier allegations of underpaying workers and ignoring COVID-19 safety rules in Leicester factories.</p>\n<p><strong>Woody''s Caravan Park:</strong> Reduced carbon emissions by 50% using electric vehicles and solar panels; pays above minimum wage; recycles all waste.</p>", "question": "According to the case studies in this card, what happened to Tesco regarding its suppliers?", "options": ["Tesco was praised for always paying its suppliers early and in full", "Tesco was found guilty of delaying payments, damaging a supplier''s cash flow", "Tesco stopped using any suppliers from developing countries entirely at all", "Tesco was the first retailer to gain full Fairtrade certification"]}'::jsonb, '{"answer": 1, "explain": "The card describes Tesco being found guilty of delaying payments to a small supplier for 24 months, damaging that supplier''s cash flow — an example of unethical supplier treatment."}'::jsonb),
('business:6-1-ethical-environmental:learn:9488d600', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "CSR and Long-Term Business Strategy", "reading": "<p><strong>Corporate Social Responsibility (CSR)</strong> is the idea that businesses should be judged on their overall contribution to society — not just on profits. Key examples:</p>\n<ul>\n<li><strong>Next plc</strong> — recognises success is judged on ethical and environmental duties, not just financial performance</li>\n<li><strong>M&S ''Plan A''</strong> — three pillars: nourishing wellbeing, transforming local communities, caring for the planet</li>\n<li><strong>AstraZeneca</strong> — has a code of ethics at the centre of all its operations</li>\n<li><strong>Costa Coffee</strong> — uses Rainforest Alliance-certified suppliers for all coffee beans worldwide</li>\n</ul>\n<p><strong>Interdependence of ethics with other business areas:</strong></p>\n<ul>\n<li><strong>Marketing</strong> — ethical sourcing improves brand image; environmental friendliness can be promoted</li>\n<li><strong>Human Resources</strong> — ethical treatment of workers improves motivation, reduces turnover, lowers recruitment costs</li>\n<li><strong>Finance</strong> — ethical/environmental practices can raise costs but also reduce tax and attract investment</li>\n<li><strong>Operations</strong> — sustainable production methods change production processes and supply chains</li>\n</ul>", "question": "According to this card, what does ''Corporate Social Responsibility'' (CSR) mean?", "options": ["Businesses should be judged only on their own annual financial profit figures each year", "Businesses should ignore environmental and ethical duties completely", "Businesses should be judged on their overall contribution to society, not just profits", "Businesses should only report their performance to their shareholders"]}'::jsonb, '{"answer": 2, "explain": "The card defines CSR as the idea that businesses should be judged on their overall contribution to society, not just on profits, citing Next plc and M&S ''Plan A'' as examples."}'::jsonb),
('business:6-1-ethical-environmental:learn:0ff8d3f4', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'learn', 'mcq', 1, '{"readingTitle": "Case Studies: Olleco & Costa Coffee", "reading": "<p><strong>Olleco (Environmental Focus):</strong><br>\n  Olleco collects used cooking oil and food waste from the catering industry and converts it into renewable energy (biofuels). Since 2006, they have grown from 1 site to 19 sites with sales exceeding £220m. <br><em>Impact:</em> While researching and developing new biofuel technology incurs massive R&D costs, their environmental focus has allowed them to survive and grow significantly in a highly competitive market.</p>\n  <p><strong>Costa Coffee (Ethical Focus):</strong><br>\n  Costa switched to using Rainforest Alliance-certified coffee beans. <br><em>Impact:</em> This ensures suppliers are treated fairly and farming is sustainable. It boosts Costa''s reputation against rivals like Starbucks, allowing them to attract ethically-minded consumers, even if the certified beans cost more to purchase.</p>", "question": "According to this card, how has Costa Coffee shown its ethical focus?", "options": ["By reducing the number of branches it operates in across the whole country", "By refusing to compete with rival coffee chains such as Starbucks", "By converting waste cooking oil into biofuels at its own sites", "By switching to Rainforest Alliance-certified coffee beans from its suppliers"]}'::jsonb, '{"answer": 3, "explain": "The card describes Costa Coffee''s ethical focus as switching to Rainforest Alliance-certified beans, ensuring fair supplier treatment and sustainable farming."}'::jsonb),
('business:6-1-ethical-environmental:misc:818f0189', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse ''Ethical'' and ''Environmental'' considerations.</p><p><strong>✅ The correct idea:</strong> ETHICAL is about how you treat PEOPLE (workers, suppliers, customers, no child labour). ENVIRONMENTAL is about how you treat the PLANET (sustainability, pollution, waste, renewable energy).</p>", "question": "What is the correct distinction between ''ethical'' and ''environmental'' considerations?", "options": ["Ethical concerns how people are treated; environmental concerns how the planet is treated", "Ethical and environmental considerations mean exactly the same thing in every business", "Ethical concerns the planet, while environmental concerns how people are treated", "Ethical only applies to customers, while environmental only applies to suppliers"]}'::jsonb, '{"answer": 0, "explain": "The card explains ethical is about treatment of people (workers, suppliers, customers), while environmental is about treatment of the planet (sustainability, pollution, waste)."}'::jsonb),
('business:6-1-ethical-environmental:misc:002104ae', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think being ethical guarantees higher profits automatically.</p><p><strong>✅ The correct idea:</strong> Being ethical usually increases COSTS (fair wages, fairtrade materials). It only increases profit IF the business can convince customers to pay a higher premium price to cover those costs.</p>", "question": "Does being ethical automatically guarantee a business higher profits?", "options": ["Yes — ethical businesses are always guaranteed higher profits than their rivals", "No — it usually raises costs, and only increases profit if customers pay a premium", "Yes — being ethical automatically removes all extra costs for a business", "No — ethical businesses can never make a profit under any circumstances"]}'::jsonb, '{"answer": 1, "explain": "The card explains ethical behaviour usually raises costs, and only increases profit if the business can convince customers to pay a higher premium price."}'::jsonb),
('business:6-1-ethical-environmental:misc:12585104', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students think non-renewable resources can be recycled forever.</p><p><strong>✅ The correct idea:</strong> Non-renewable resources (like coal and oil) are burned/used once and are gone forever. Renewable resources (like wind and solar) never run out.</p>", "question": "Can non-renewable resources be recycled and reused forever?", "options": ["Yes — non-renewable resources can be recycled indefinitely without any limit", "Yes — but only renewable resources like oil can be recycled forever", "No — non-renewable resources like coal and oil are used once and are gone", "No — renewable resources like wind and solar also run out eventually"]}'::jsonb, '{"answer": 2, "explain": "The card explains non-renewable resources like coal and oil are burned or used once and are gone forever, unlike renewable resources such as wind and solar which never run out."}'::jsonb),
('business:6-1-ethical-environmental:misc:ddd5d0a9', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''analyse'' questions, students just state ''it gives a good reputation''.</p><p><strong>✅ The correct idea:</strong> You must explain the BUSINESS IMPACT. ''It improves reputation (U), which attracts more ethically-minded customers (APP), leading to an increase in sales revenue and market share (AN).''</p>", "question": "What must a full ''analyse'' answer include, beyond stating ''it gives a good reputation''?", "options": ["Only the same statement repeated using slightly different wording again", "A complete list of every possible ethical consideration a business could make", "A definition of environmental considerations rather than ethical ones", "The business impact — e.g. how reputation leads to increased sales revenue"]}'::jsonb, '{"answer": 3, "explain": "The card explains you must explain the business impact — reputation (U) attracting ethical customers (APP) leading to increased sales revenue and market share (AN)."}'::jsonb),
('business:6-1-ethical-environmental:misc:6a893784', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Obeying the law (e.g. paying minimum wage, not discriminating) counts as ethical behaviour.</p><p><strong>✅ The correct idea:</strong> Ethics is about what a firm does OVER AND ABOVE what the law requires. Paying the minimum wage is a legal obligation — not an ethical choice. Ethical behaviour means going further: paying a living wage, treating suppliers fairly, and choosing Fairtrade even when not legally required.</p>", "question": "Does obeying the law, such as paying minimum wage, count as ethical behaviour?", "options": ["No — ethics is about going over and above what the law legally requires", "Yes — any legal requirement automatically counts as ethical behaviour too", "Yes — minimum wage is specifically an ethical rather than legal requirement", "No — ethical behaviour can only ever apply to environmental issues instead"]}'::jsonb, '{"answer": 0, "explain": "The card explains ethics is about what a firm does over and above the law — paying minimum wage is a legal obligation, not an ethical choice."}'::jsonb),
('business:6-1-ethical-environmental:misc:6f53237c', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Environmental considerations and ethical considerations are the same thing and can be used interchangeably.</p><p><strong>✅ The correct idea:</strong> They are different. ETHICAL considerations concern the treatment of people — workers, suppliers and customers (fair pay, child labour, false claims). ENVIRONMENTAL considerations concern the natural world — pollution, global warming, waste disposal, sustainable production. Mixing them up loses marks in the exam.</p>", "question": "Are ethical and environmental considerations the same thing that can be used interchangeably?", "options": ["Yes — both terms describe exactly the same set of business considerations", "No — ethical concerns people, while environmental concerns the natural world", "Yes — environmental considerations are simply one type of ethical consideration", "No — ethical considerations only ever apply to a business''s suppliers alone"]}'::jsonb, '{"answer": 1, "explain": "The card explains ethical considerations concern the treatment of people, while environmental considerations concern the natural world — mixing them up loses exam marks."}'::jsonb),
('business:6-1-ethical-environmental:misc:c255eb08', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Being ethical is always bad for business because it increases costs.</p><p><strong>✅ The correct idea:</strong> Being ethical has BOTH costs and benefits. Yes, it raises costs (higher wages, Fairtrade prices) but it also brings benefits: improved reputation, increased sales from ethical consumers, more motivated staff (lower turnover and recruitment costs), and long-term survival. The net effect depends on the market and the business.</p>", "question": "Is being ethical always bad for business because it increases costs?", "options": ["Yes — being ethical only ever increases costs with no benefits at all whatsoever", "No — being ethical never increases a business''s costs in any way at all", "No — it has both costs and benefits, such as improved reputation and sales", "Yes — ethical businesses always make a loss in the long run overall"]}'::jsonb, '{"answer": 2, "explain": "The card explains being ethical has both costs (higher wages, Fairtrade prices) and benefits (reputation, sales, motivation, long-term survival) — the net effect depends on the market."}'::jsonb),
('business:6-1-ethical-environmental:misc:0f0668bb', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using robotics instead of workers is an example of ethical treatment of the workforce.</p><p><strong>✅ The correct idea:</strong> Using robotics is a business OPERATIONS/TECHNOLOGY decision, not an ethical one. Ethical treatment of workers is about HOW existing and future human workers are treated — pay, hours, safety, fairness. Replacing workers with machines is a productivity/cost decision, not an ethical employer practice.</p>", "question": "Is using robotics instead of workers an example of ethical treatment of the workforce?", "options": ["Yes — replacing workers with robots is always considered ethical practice", "Yes — robotics automatically improves the pay and safety of remaining staff", "No — but only because robots are classed as an environmental consideration", "No — it is an operations/technology decision, not an ethical one at all"]}'::jsonb, '{"answer": 3, "explain": "The card explains using robotics is an operations/technology decision about productivity and cost, not an ethical decision about how human workers are treated."}'::jsonb),
('business:6-1-ethical-environmental:misc:59ec3c37', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For ''analyse one benefit of being ethical'' (3 marks), stating ''the business gets a better reputation'' is enough.</p><p><strong>✅ The correct idea:</strong> 3 marks require: Understanding (1) — explain what the ethical action is. Application (1) — link to the specific business using case study detail. Analysis (1) — show the business IMPACT (e.g. ''this leads to increased sales and higher revenue''). A bare statement earns only 1 mark. You must chain: ethical action → intermediate effect → business consequence.</p>", "question": "Why does ''the business gets a better reputation'' alone not earn all 3 marks?", "options": ["It is missing application to the specific business and analysis of the impact", "It is factually incorrect, since ethical businesses never gain a better reputation", "It only ever applies to environmental considerations, not ethical ones", "It already contains full understanding, application and analysis in one sentence"]}'::jsonb, '{"answer": 0, "explain": "The card explains a bare statement earns only 1 mark — full marks require Application (link to the specific business) and Analysis (the business impact) as well."}'::jsonb),
('business:6-1-ethical-environmental:misc:b0e81ebc', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The Fairtrade Mark guarantees that a product is organic and environmentally produced.</p><p><strong>✅ The correct idea:</strong> The Fairtrade Mark specifically guarantees that a FAIR PRICE was paid to the farmers/suppliers in developing countries. It is an ETHICAL guarantee about fair treatment of suppliers — not a guarantee about organic farming or environmental production methods, though these may overlap.</p>", "question": "What does the Fairtrade Mark actually guarantee?", "options": ["That a product was grown organically without any pesticides or chemicals", "That a fair price was paid to farmers and suppliers in developing countries", "That a product was produced using only renewable sources of energy", "That a product contains no ingredients sourced from developing countries"]}'::jsonb, '{"answer": 1, "explain": "The card explains the Fairtrade Mark is an ethical guarantee about fair supplier treatment — not a guarantee about organic farming or environmental production methods."}'::jsonb),
('business:6-1-ethical-environmental:misc:3040d6cb', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a 9-mark evaluate question, listing as many ethical and environmental points as possible will score high marks.</p><p><strong>✅ The correct idea:</strong> 9-mark questions require a structured chain: K (define) → U (explain) → APP x2 (use the case study twice) → AN x2 (show the business impact) → EVAL (make a judgement and justify it using the context). Listing generic points without application to the case study earns very few marks. Depth and context always outperform breadth.</p>", "question": "For a 9-mark evaluate question, is listing as many points as possible the best strategy?", "options": ["Yes — the more points listed, the higher the mark awarded every single time", "Yes — application to the case study is not required in a 9-mark question", "No — a structured chain with application and analysis scores far more highly", "No — but only because 9-mark questions do not require any evaluation at all"]}'::jsonb, '{"answer": 2, "explain": "The card explains 9-mark questions require a structured K-U-APP-AN-EVAL chain — listing generic points without case study application scores very few marks."}'::jsonb),
('business:6-1-ethical-environmental:tips:d2cdcce2', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "State / Identify (1 mark) — Naming Considerations", "reading": "<p>If asked to state an <strong>Ethical</strong> consideration, use: Fair wages, child labour, Fairtrade, treating suppliers fairly.</p>\n  <p>If asked to state an <strong>Environmental</strong> consideration, use: Waste disposal, pollution, sustainability, carbon emissions.</p>", "question": "According to this card, which of these would correctly answer a question asking for an environmental consideration?", "options": ["Fair wages, child labour, Fairtrade or treating suppliers fairly", "Break-even, cash flow, profit margin or average rate of return", "Market segmentation, market research, product life cycle or price", "Waste disposal, pollution, sustainability or carbon emissions"]}'::jsonb, '{"answer": 3, "explain": "The card lists waste disposal, pollution, sustainability and carbon emissions as environmental considerations; the other options are ethical, finance, or marketing terms."}'::jsonb),
('business:6-1-ethical-environmental:tips:3011e9f8', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Analyse (3 marks) — Analysing the Disadvantages", "reading": "<p>Always remember that Ethics and Environment cost money.</p>\n  <p><strong>Structure:</strong> \"One reason not to be environmentally friendly is the high initial cost (U). For example, installing solar panels to power the caravan park is expensive (APP). This drains cash flow and could reduce short-term profit margins (AN).\"</p>", "question": "According to this card''s example, what is the Understanding (U) point in the solar panel argument?", "options": ["One reason not to be environmentally friendly is the high initial cost", "Installing solar panels to power the caravan park is expensive to do", "This drains cash flow and could reduce short-term profit margins here", "The caravan park has fully repaid its solar panel investment already"]}'::jsonb, '{"answer": 0, "explain": "The card''s model structure identifies ''the high initial cost'' as the Understanding (U) point, before the Application (solar panels) and Analysis (drains cash flow) steps."}'::jsonb),
('business:6-1-ethical-environmental:tips:51a78ba4', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate (9 marks) — Using the Context Data", "reading": "<p>In large questions (like the Costa Coffee 9-marker), you MUST use the data provided.</p>\n  <p>If the text says Costa has 2,100 branches or competes with Starbucks, use those exact facts in your Application (APP) sentences to secure top marks. Do not write a generic essay about ethics.</p>", "question": "According to this card, what must a strong Costa Coffee 9-mark answer avoid writing?", "options": ["Any reference at all to the number of branches Costa Coffee operates", "A generic essay about ethics that does not use the specific case study facts", "Any comparison at all between Costa Coffee and its rival Starbucks", "A final judgement given at the end of the answer about Costa Coffee''s ethics"]}'::jsonb, '{"answer": 1, "explain": "The card warns you must use exact facts from the text, such as branch numbers or the Starbucks comparison, rather than writing a generic essay about ethics."}'::jsonb),
('business:6-1-ethical-environmental:tips:95471766', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Identify two ethical/environmental considerations (2 marks)", "reading": "<p><strong>Ethical:</strong> Treatment of workers, Treatment of suppliers, Treatment of customers, Sourcing of materials.</p>\n  <p><strong>Environmental:</strong> Sustainability, Waste disposal, Pollution, Climate change.</p>\n  <p><em>Tip:</em> Give the CATEGORY name — not just an example. e.g., ''Treatment of workers'' earns the mark; ''paying fair wages'' alone may not unless the question asks you to explain.</p>", "question": "According to this card, what should you give when asked to identify a consideration?", "options": ["A specific example only, and never the broader category name", "A full paragraph explaining the consideration in complete detail", "The category name itself, not just a specific example of it", "A calculation showing the cost of the consideration in pounds"]}'::jsonb, '{"answer": 2, "explain": "The card advises giving the category name — e.g. ''Treatment of workers'' — since a specific example alone may not earn the mark unless the question asks you to explain."}'::jsonb),
('business:6-1-ethical-environmental:tips:fa0545a3', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one benefit/disadvantage of being ethical (3 marks)", "reading": "<p><strong>Structure:</strong></p>\n  <ul>\n    <li><strong>(U)</strong> State and explain the benefit e.g., ''ethical businesses often gain an improved reputation''.</li>\n    <li><strong>(APP)</strong> Link to the specific business — e.g., ''Pukka Teas'' turnover rose from £9m to £45m''.</li>\n    <li><strong>(AN)</strong> Show the business impact — ''this increased revenue can be reinvested to fund further growth''.</li>\n  </ul>\n  <p>A chain of three linked points earns all 3 marks.</p>", "question": "In the Pukka Teas example on this card, which part is the Application (APP) point?", "options": ["Ethical businesses often gain an improved reputation as a result", "This increased revenue can be reinvested to fund further growth plans", "A chain of three linked points together earns all three marks available", "Pukka Teas'' turnover rose from nine million pounds to forty-five million"]}'::jsonb, '{"answer": 3, "explain": "The card identifies Pukka Teas'' turnover growth (£9m to £45m) as the Application point, linking the general Understanding point to a specific business."}'::jsonb),
('business:6-1-ethical-environmental:tips:f293ee58', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Most Repeated Question Type — Analyse one method of sustainable production (3 marks)", "reading": "<p>Name the method (e.g., solar panels / renewable energy). Apply it to the specific business in the case study. Analyse the business impact — usually reduced costs OR improved reputation &rarr; increased sales.</p>\n  <p><strong>Example:</strong> ''Aston Martin could install solar panels (K) to power its Warwickshire production site (APP) which would cut energy costs and reduce its carbon footprint, improving its environmental image (AN).''</p>", "question": "In the Aston Martin example on this card, what is being analysed as the business impact?", "options": ["Cutting energy costs and improving its environmental image as a result", "Installing solar panels at its Warwickshire production site directly", "The general concept of renewable energy as a sustainable method overall", "The specific geographic location of Aston Martin''s production site"]}'::jsonb, '{"answer": 0, "explain": "The card''s Analysis (AN) step identifies cutting energy costs and improving environmental image as the business impact of installing solar panels."}'::jsonb),
('business:6-1-ethical-environmental:tips:6eea54e1', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "9-Mark Evaluate Question — Evaluate whether ethical/environmental considerations conflict with shareholder objectives", "reading": "<p><strong>Structure:</strong></p>\n  <ul>\n    <li><strong>K:</strong> Define ethics.</li>\n    <li><strong>U:</strong> Explain how ethical practices work (e.g., fair wages, Fairtrade sourcing).</li>\n    <li><strong>APP x2:</strong> Use the case study to show two specific ethical actions.</li>\n    <li><strong>AN x2:</strong> Show how each raises costs or reduces profits — conflicting with shareholder profit goals.</li>\n    <li><strong>EVAL:</strong> Judge the EXTENT of conflict — e.g., in the LONG TERM, ethical businesses like Pukka Teas may generate more profit through increased sales, but SHORT TERM costs rise and dividends may fall.</li>\n  </ul>", "question": "According to this card''s example, how might ethical practices conflict with shareholder objectives?", "options": ["They have no effect on shareholder objectives in either the short or long term", "They raise costs or reduce profits in the short term, before benefits appear", "They guarantee higher dividends to shareholders immediately every single year", "They remove the need for a business to consider its costs at all in future"]}'::jsonb, '{"answer": 1, "explain": "The card explains ethical practices can raise costs or reduce profits short-term, conflicting with shareholder goals, even though long-term profit may rise through increased sales."}'::jsonb),
('business:6-1-ethical-environmental:tips:1c68fb91', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "9-Mark Evaluate Question — Evaluate how environmental considerations affect the marketing mix", "reading": "<p>Link environment to each P:</p>\n  <ul>\n    <li><strong>Product:</strong> May need to redesign packaging (e.g., Pukka Pies replacing non-recyclable plastics).</li>\n    <li><strong>Price:</strong> May need to rise to cover eco costs.</li>\n    <li><strong>Place:</strong> Distribution using lower-emission vehicles.</li>\n    <li><strong>Promotion:</strong> Green credentials become a marketing message.</li>\n  </ul>\n  <p><strong>Evaluate</strong> which P is most affected, using case study figures. e.g., ''Price is most affected as no waste to landfill reduces costs, offsetting the cost of new packaging.''</p>", "question": "In this card''s example, why might ''Price'' be judged the most affected element of the marketing mix?", "options": ["Price is never affected by any environmental consideration at all here", "Promotion is always more affected than price by any environmental change", "No waste to landfill reduces costs, offsetting the cost of new packaging", "Place is always more affected than price by any environmental change"]}'::jsonb, '{"answer": 2, "explain": "The card''s example judges Price as most affected because reduced landfill waste cuts costs, offsetting the cost of new eco-friendly packaging."}'::jsonb),
('business:6-1-ethical-environmental:tips:f9f8f8a5', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Examiner Warning — Do NOT confuse ethical with legal, or ethical with environmental", "reading": "<p>Three common errors that lose marks:</p>\n  <ol>\n    <li><strong>Describing legal compliance</strong> (e.g., paying minimum wage) as an ethical choice — it is a legal duty. Ethics goes BEYOND the law.</li>\n    <li><strong>Writing about pollution and sustainability</strong> when asked about ethics — these are environmental issues.</li>\n    <li><strong>Writing about fair pay and child labour</strong> when asked about environmental considerations — these are ethical issues.</li>\n  </ol>", "question": "According to this card, why is describing minimum wage payment as an ''ethical choice'' a common error?", "options": ["Minimum wage payments are actually classed as an environmental consideration", "Minimum wage does not exist as a legal requirement in any country at all", "Ethics and legal compliance are officially treated as the same concept", "Paying minimum wage is a legal duty, and ethics goes beyond the law"]}'::jsonb, '{"answer": 3, "explain": "The card lists this as a common error — describing legal compliance like minimum wage as an ethical choice, when ethics specifically goes beyond what the law requires."}'::jsonb),
('business:6-1-ethical-environmental:tips:33e71d06', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Evaluation Tip — Short-term costs vs. long-term benefits — the key evaluation point", "reading": "<p>The strongest evaluations in this unit recognise that:</p>\n  <ul>\n    <li><strong>In the SHORT TERM:</strong> ethical/environmental practices raise costs, may reduce profits, and could conflict with shareholder objectives.</li>\n    <li><strong>In the LONG TERM:</strong> they improve reputation, increase sales, motivate workers, reduce turnover, attract investors, and can lower costs (e.g., solar panels).</li>\n  </ul>\n  <p>Always judge whether short-term costs are outweighed by long-term benefits, using the specific business context.</p>", "question": "According to this card, what should the strongest evaluations recognise?", "options": ["Short-term costs may be outweighed by long-term benefits, given the context", "Short-term costs always outweigh every possible long-term benefit available", "Long-term benefits never apply to ethical or environmental practices at all", "Ethical and environmental practices have no effect on costs whatsoever"]}'::jsonb, '{"answer": 0, "explain": "The card advises the strongest evaluations judge whether short-term costs are outweighed by long-term benefits, using the specific business context."}'::jsonb),
('business:6-1-ethical-environmental:tips:f5568b22', 'business', 'business:6-1-ethical-environmental', '6.1 Ethical & Environmental', 'tips', 'mcq', 1, '{"readingTitle": "Case Study Application Tip — Always use specific case study numbers", "reading": "<p>Application marks are ONLY awarded when you use the specific details from the case study — not generic statements.</p>\n  <ul>\n    <li><strong>Wrong:</strong> ''The business is growing.''<br><strong>Right:</strong> ''Pukka Teas'' turnover rose from £9m in 2012 to £45m in 2019.''</li>\n    <li><strong>Wrong:</strong> ''The business paid money to a fund.''<br><strong>Right:</strong> ''Pukka Teas paid £148,000 into the Fairtrade community fund in 2017.''</li>\n  </ul>\n  <p>Always quote figures, names and specific facts from the text.</p>", "question": "According to this card, when are Application marks actually awarded?", "options": ["Whenever a generic statement like ''the business is growing'' is used instead", "Only when specific case study details, figures or names are actually used", "Only when no numbers or figures are mentioned anywhere in the answer", "Automatically, regardless of whether any case study detail is used at all"]}'::jsonb, '{"answer": 1, "explain": "The card explains Application marks are only awarded when specific case study details are used — e.g. ''Pukka Teas'' turnover rose from £9m to £45m'' rather than a generic claim."}'::jsonb),
